// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: 'ecclesiastes',
  name: 'Eclesiastes',
  englishName: 'Ecclesiastes',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'The words of the Preacher, the son of David, king in Jerusalem:', pt: 'Palavras do pregador, filho de Davi, rei em Jerusalém.' },
      { v: 2, en: '“Vanity of vanities,” says the Preacher; “Vanity of vanities, all is vanity.”', pt: 'Vaidade de vaidades, diz o pregador; vaidade de vaidades, tudo é vaidade.' },
      { v: 3, en: 'What does man gain from all his labor in which he labors under the sun?', pt: 'Que proveito tem o homem, de todo o seu trabalho, com que se afadiga debaixo do sol?' },
      { v: 4, en: 'One generation goes, and another generation comes; but the earth remains forever.', pt: 'Uma geração vai-se, e outra geração vem, mas a terra permanece para sempre.' },
      { v: 5, en: 'The sun also rises, and the sun goes down, and hurries to its place where it rises.', pt: 'O sol nasce, e o sol se põe, e corre de volta ao seu lugar donde nasce.' },
      { v: 6, en: 'The wind goes toward the south, and turns around to the north. It turns around continually as it goes, and the wind returns again to its courses.', pt: 'O vento vai para o sul, e faz o seu giro vai para o norte; volve-se e revolve-se na sua carreira, e retoma os seus circuitos.' },
      { v: 7, en: 'All the rivers run into the sea, yet the sea is not full. To the place where the rivers flow, there they flow again.', pt: 'Todos os ribeiros vão para o mar, e contudo o mar não se enche; ao lugar para onde os rios correm, para ali continuam a correr.' },
      { v: 8, en: 'All things are full of weariness beyond uttering. The eye is not satisfied with seeing, nor the ear filled with hearing.', pt: 'Todas as coisas estão cheias de cansaço; ninguém o pode exprimir: os olhos não se fartam de ver, nem os ouvidos se enchem de ouvir.' },
      { v: 9, en: 'That which has been is that which shall be; and that which has been done is that which shall be done: and there is no new thing under the sun.', pt: 'O que tem sido, isso é o que há de ser; e o que se tem feito, isso se tornará a fazer; nada há que seja novo debaixo do sol.' },
      { v: 10, en: 'Is there a thing of which it may be said, “Behold, this is new?” It has been long ago, in the ages which were before us.', pt: 'Há alguma coisa de que se possa dizer: Voê, isto é novo? ela já existiu nos séculos que foram antes de nós.' },
      { v: 11, en: 'There is no memory of the former; neither shall there be any memory of the latter that are to come, among those that shall come after.', pt: 'Já não há lembrança das gerações passadas; nem das gerações futuras haverá lembrança entre os que virão depois delas.' },
      { v: 12, en: 'I, the Preacher, was king over Israel in Jerusalem.', pt: 'Eu, o pregador, fui rei sobre Israel em Jerusalém.' },
      { v: 13, en: 'I applied my heart to seek and to search out by wisdom concerning all that is done under the sky. It is a heavy burden that God has given to the sons of men to be afflicted with.', pt: 'E apliquei o meu coração a inquirir e a investigar com sabedoria a respeito de tudo quanto se faz debaixo do céu; essa enfadonha ocupação deu Deus aos filhos dos homens para nela se exercitarem.' },
      { v: 14, en: 'I have seen all the works that are done under the sun; and behold, all is vanity and a chasing after wind.', pt: 'Atentei para todas as obras que se e fazem debaixo do sol; e eis que tudo era vaidade e desejo vão.' },
      { v: 15, en: 'That which is crooked can’t be made straight; and that which is lacking can’t be counted.', pt: 'O que é torto não se pode endireitar; o que falta não se pode enumerar.' },
      { v: 16, en: 'I said to myself, “Behold, I have obtained for myself great wisdom above all who were before me in Jerusalem. Yes, my heart has had great experience of wisdom and knowledge.”', pt: 'Falei comigo mesmo, dizendo: Eis que eu me engrandeci, e sobrepujei em sabedoria a todos os que houve antes de mim em Jerusalém; na verdade, tenho tido larga experiência da sabedoria e do conhecimento.' },
      { v: 17, en: 'I applied my heart to know wisdom, and to know madness and folly. I perceived that this also was a chasing after wind.', pt: 'E apliquei o coração a conhecer a sabedoria e a conhecer os desvarios e as loucuras; e vim a saber que também isso era desejo vao.' },
      { v: 18, en: 'For in much wisdom is much grief; and he who increases knowledge increases sorrow.', pt: 'Porque na muita sabedoria há muito enfado; e o que aumenta o conhecimento aumenta a tristeza.' },
    ],
    2: [
      { v: 1, en: 'I said in my heart, “Come now, I will test you with mirth: therefore enjoy pleasure”; and behold, this also was vanity.', pt: 'Disse eu a mim mesmo: Ora vem, eu te provarei com a alegria; portanto goza o prazer; mas eis que também isso era vaidade.' },
      { v: 2, en: 'I said of laughter, “It is foolishness”; and of mirth, “What does it accomplish?”', pt: 'Do riso disse: Está doido; e da alegria: De que serve estar.' },
      { v: 3, en: 'I searched in my heart how to cheer my flesh with wine, my heart yet guiding me with wisdom, and how to lay hold of folly, until I might see what it was good for the sons of men that they should do under heaven all the days of their lives.', pt: 'Busquei no meu coração como estimular com vinho a minha carne, sem deixar de me guiar pela sabedoria, e como me apoderar da estultícia, até ver o que era bom que os filhos dos homens fizessem debaixo do céu, durante o número dos dias de sua vida.' },
      { v: 4, en: 'I made myself great works. I built myself houses. I planted myself vineyards.', pt: 'Fiz para mim obras magníficas: edifiquei casas, plantei vinhas;' },
      { v: 5, en: 'I made myself gardens and parks, and I planted trees in them of all kinds of fruit.', pt: 'fiz hortas e jardins, e plantei neles árvores frutíferas de todas as espécies.' },
      { v: 6, en: 'I made myself pools of water, to water from it the forest where trees were reared.', pt: 'Fiz tanques de águas, para deles regar o bosque em que reverdeciam as árvores.' },
      { v: 7, en: 'I bought male servants and female servants, and had servants born in my house. I also had great possessions of herds and flocks, above all who were before me in Jerusalem;', pt: 'Comprei servos e servas, e tive servos nascidos em casa; também tive grandes possessões de gados e de rebanhos, mais do que todos os que houve antes de mim em Jerusalém.' },
      { v: 8, en: 'I also gathered silver and gold for myself, and the treasure of kings and of the provinces. I got myself male and female singers, and the delights of the sons of men—musical instruments, and that of all sorts.', pt: 'Ajuntei também para mim prata e ouro, e tesouros dos reis e das províncias; provi-me de cantores e cantoras, e das delícias dos filhos dos homens, concubinas em grande número.' },
      { v: 9, en: 'So I was great, and increased more than all who were before me in Jerusalem. My wisdom also remained with me.', pt: 'Assim me engrandeci, e me tornei mais rico do que todos os que houve antes de mim em Jerusalém; perseverou também comigo a minha sabedoria.' },
      { v: 10, en: 'Whatever my eyes desired, I didn’t keep from them. I didn’t withhold my heart from any joy, for my heart rejoiced because of all my labor, and this was my portion from all my labor.', pt: 'E tudo quanto desejaram os meus olhos não lho neguei, nem privei o meu coração de alegria alguma; pois o meu coração se alegrou por todo o meu trabalho, e isso foi o meu proveito de todo o meu trabalho.' },
      { v: 11, en: 'Then I looked at all the works that my hands had worked, and at the labor that I had labored to do; and behold, all was vanity and a chasing after wind, and there was no profit under the sun.', pt: 'Então olhei eu para todas as obras que as minhas mãos haviam feito, como também para o trabalho que eu aplicara em fazê-las; e eis que tudo era vaidade e desejo vão, e proveito nenhum havia debaixo do sol.' },
      { v: 12, en: 'I turned myself to consider wisdom, madness, and folly: for what can the king’s successor do? Just that which has been done long ago.', pt: 'Virei-me para contemplar a sabedoria, e a loucura, e a estultícia; pois que fará o homem que seguir ao rei? O mesmo que já se fez!' },
      { v: 13, en: 'Then I saw that wisdom excels folly, as far as light excels darkness.', pt: 'Então vi eu que a sabedoria é mais excelente do que a estultícia, quanto a luz é mais excelente do que as trevas.' },
      { v: 14, en: 'The wise man’s eyes are in his head, and the fool walks in darkness—and yet I perceived that one event happens to them all.', pt: 'Os olhos do sábio estão na sua cabeça, mas o louco anda em trevas; contudo percebi que a mesma coisa lhes sucede a ambos.' },
      { v: 15, en: 'Then I said in my heart, “As it happens to the fool, so will it happen even to me; and why was I then more wise?” Then I said in my heart that this also is vanity.', pt: 'Pelo que eu disse no meu coração: Como acontece ao estulto, assim me sucederá a mim; por que então busquei eu mais a sabedoria; Então respondi a mim mesmo que também isso era vaidade.' },
      { v: 16, en: 'For of the wise man, even as of the fool, there is no memory for ever, since in the days to come all will have been long forgotten. Indeed, the wise man must die just like the fool!', pt: 'Pois do sábio, bem como do estulto, a memória não durará para sempre; porquanto de tudo, nos dias futuros, total esquecimento haverá. E como morre o sábio, assim morre o estulto!' },
      { v: 17, en: 'So I hated life, because the work that is worked under the sun was grievous to me; for all is vanity and a chasing after wind.', pt: 'Pelo que aborreci a vida, porque a obra que se faz debaixo do sol me era penosa; sim, tudo é vaidade e desejo vão.' },
      { v: 18, en: 'I hated all my labor in which I labored under the sun, because I must leave it to the man who comes after me.', pt: 'Também eu aborreci todo o meu trabalho em que me afadigara debaixo do sol, visto que tenho de deixá-lo ao homem que virá depois de mim.' },
      { v: 19, en: 'Who knows whether he will be a wise man or a fool? Yet he will have rule over all of my labor in which I have labored, and in which I have shown myself wise under the sun. This also is vanity.', pt: 'E quem sabe se será sábio ou estulto? Contudo, ele se assenhoreará de todo o meu trabalho em que me afadiguei, e em que me houve sabiamente debaixo do sol; também isso é vaidade.' },
      { v: 20, en: 'Therefore I began to cause my heart to despair concerning all the labor in which I had labored under the sun.', pt: 'Pelo que eu me volvi e entreguei o meu coração ao desespero no tocante a todo o trabalho em que me afadigara debaixo do sol.' },
      { v: 21, en: 'For there is a man whose labor is with wisdom, with knowledge, and with skillfulness; yet he shall leave it for his portion to a man who has not labored for it. This also is vanity and a great evil.', pt: 'Porque há homem cujo trabalho é feito com sabedoria, e ciência, e destreza; contudo, deixará o fruto do seu labor para ser porção de quem não trabalhou nele; também isso é vaidade e um grande mal.' },
      { v: 22, en: 'For what has a man of all his labor, and of the striving of his heart, in which he labors under the sun?', pt: 'Pois, que alcança o homem com todo o seu trabalho e com a fadiga em que ele anda trabalhando debaixo do sol?' },
      { v: 23, en: 'For all his days are sorrows, and his travail is grief; yes, even in the night his heart takes no rest. This also is vanity.', pt: 'Porque todos os seus dias são dores, e o seu trabalho é vexação; nem de noite o seu coração descansa. Também isso é vaidade.' },
      { v: 24, en: 'There is nothing better for a man than that he should eat and drink, and make his soul enjoy good in his labor. This also I saw, that it is from the hand of God.', pt: 'Não há nada melhor para o homem do que comer e beber, e fazer que a sua alma goze do bem do seu trabalho. Vi que também isso vem da mão de Deus.' },
      { v: 25, en: 'For who can eat, or who can have enjoyment, more than I?', pt: 'Pois quem pode comer, ou quem pode gozar. melhor do que eu?' },
      { v: 26, en: 'For to the man who pleases him, God gives wisdom, knowledge, and joy; but to the sinner he gives travail, to gather and to heap up, that he may give to him who pleases God. This also is vanity and a chasing after wind.', pt: 'Porque ao homem que lhe agrada, Deus dá sabedoria, e conhecimento, e alegria; mas ao pecador dá trabalho, para que ele ajunte e amontoe, a fim de dá-lo àquele que agrada a Deus: Também isso é vaidade e desejo vão.' },
    ],
    3: [
      { v: 1, en: 'For everything there is a season, and a time for every purpose under heaven:', pt: 'Tudo tem a sua ocasião própria, e há tempo para todo propósito debaixo do céu.' },
      { v: 2, en: 'a time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;', pt: 'Há tempo de nascer, e tempo de morrer; tempo de plantar, e tempo de arrancar o que se plantou;' },
      { v: 3, en: 'a time to kill, and a time to heal; a time to break down, and a time to build up;', pt: 'tempo de matar, e tempo de curar; tempo de derribar, e tempo de edificar;' },
      { v: 4, en: 'a time to weep, and a time to laugh; a time to mourn, and a time to dance;', pt: 'tempo de chorar, e tempo de rir; tempo de prantear, e tempo de dançar;' },
      { v: 5, en: 'a time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;', pt: 'tempo de espalhar pedras, e tempo de ajuntar pedras; tempo de abraçar, e tempo de abster-se de abraçar;' },
      { v: 6, en: 'a time to seek, and a time to lose; a time to keep, and a time to cast away;', pt: 'tempo de buscar, e tempo de perder; tempo de guardar, e tempo de deitar fora;' },
      { v: 7, en: 'a time to tear, and a time to sew; a time to keep silence, and a time to speak;', pt: 'tempo de rasgar, e tempo de coser; tempo de estar calado, e tempo de falar;' },
      { v: 8, en: 'a time to love, and a time to hate; a time for war, and a time for peace.', pt: 'tempo de amar, e tempo de odiar; tempo de guerra, e tempo de paz.' },
      { v: 9, en: 'What profit has he who works in that in which he labors?', pt: 'Que proveito tem o trabalhador naquilo em que trabalha?' },
      { v: 10, en: 'I have seen the burden which God has given to the sons of men to be afflicted with.', pt: 'Tenho visto o trabalho penoso que Deus deu aos filhos dos homens para nele se exercitarem.' },
      { v: 11, en: 'He has made everything beautiful in its time. He has also set eternity in their hearts, yet so that man can’t find out the work that God has done from the beginning even to the end.', pt: 'Tudo fez formoso em seu tempo; também pôs na mente do homem a idéia da eternidade, se bem que este não possa descobrir a obra que Deus fez desde o princípio até o fim.' },
      { v: 12, en: 'I know that there is nothing better for them than to rejoice, and to do good as long as they live.', pt: 'Sei que não há coisa melhor para eles do que se regozijarem e fazerem o bem enquanto viverem;' },
      { v: 13, en: 'Also that every man should eat and drink, and enjoy good in all his labor, is the gift of God.', pt: 'e também que todo homem coma e beba, e goze do bem de todo o seu trabalho é dom de Deus.' },
      { v: 14, en: 'I know that whatever God does, it shall be forever. Nothing can be added to it, nor anything taken from it; and God has done it, that men should fear before him.', pt: 'Eu sei que tudo quanto Deus faz durará eternamente; nada se lhe pode acrescentar, e nada se lhe pode tirar; e isso Deus faz para que os homens temam diante dele:' },
      { v: 15, en: 'That which is has been long ago, and that which is to be has been long ago: and God seeks again that which is passed away.', pt: 'O que é, já existiu; e o que há de ser, também já existiu; e Deus procura de novo o que ja se passou.' },
      { v: 16, en: 'Moreover I saw under the sun, in the place of justice, that wickedness was there; and in the place of righteousness, that wickedness was there.', pt: 'Vi ainda debaixo do sol que no lugar da retidão estava a impiedade; e que no lugar da justiça estava a impiedade ainda.' },
      { v: 17, en: 'I said in my heart, “God will judge the righteous and the wicked; for there is a time there for every purpose and for every work.”', pt: 'Eu disse no meu coração: Deus julgará o justo e o ímpio; porque há um tempo para todo propósito e para toda obra.' },
      { v: 18, en: 'I said in my heart, “As for the sons of men, God tests them, so that they may see that they themselves are like animals.', pt: 'Disse eu no meu coração: Isso é por causa dos filhos dos homens, para que Deus possa prová-los, e eles possam ver que são em si mesmos como os brutos.' },
      { v: 19, en: 'For that which happens to the sons of men happens to animals. Even one thing happens to them. As the one dies, so the other dies. Yes, they have all one breath; and man has no advantage over the animals: for all is vanity.', pt: 'Pois o que sucede aos filhos dos homens, isso mesmo também sucede aos brutos; uma e a mesma coisa lhes sucede; como morre um, assim morre o outro; todos têm o mesmo fôlego; e o homem não tem vantagem sobre os brutos; porque tudo é vaidade.' },
      { v: 20, en: 'All go to one place. All are from the dust, and all turn to dust again.', pt: 'Todos vão para um lugar; todos são pó, e todos ao pó tornarão.' },
      { v: 21, en: 'Who knows the spirit of man, whether it goes upward, and the spirit of the animal, whether it goes downward to the earth?”', pt: 'Quem sabe se o espírito dos filhos dos homens vai para cima, e se o espírito dos brutos desce para a terra?' },
      { v: 22, en: 'Therefore I saw that there is nothing better, than that a man should rejoice in his works; for that is his portion: for who can bring him to see what will be after him?', pt: 'Pelo que tenho visto que não há coisa melhor do que alegrar-se o homem nas suas obras; porque esse é o seu quinhão; pois quem o fará voltar para ver o que será depois dele?' },
    ],
    4: [
      { v: 1, en: 'Then I returned and saw all the oppressions that are done under the sun: and behold, the tears of those who were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter.', pt: 'Depois volvi-me, e atentei para todas as opressões que se fazem debaixo do sol; e eis as lágrimas dos oprimidos, e eles não tinham consolador; do lado dos seus opressores havia poder; mas eles não tinham consolador.' },
      { v: 2, en: 'Therefore I praised the dead who have been long dead more than the living who are yet alive.', pt: 'Pelo que julguei mais felizes os que já morreram, do que os que vivem ainda.' },
      { v: 3, en: 'Yes, better than them both is him who has not yet been, who has not seen the evil work that is done under the sun.', pt: 'E melhor do que uns e outros é aquele que ainda não é, e que não viu as más obras que se fazem debaixo do sol.' },
      { v: 4, en: 'Then I saw all the labor and achievement that is the envy of a man’s neighbor. This also is vanity and a striving after wind.', pt: 'Também vi eu que todo trabalho e toda destreza em obras provêm da inveja que o homem tem do seu próximo. Também isso é e vaidade e desejo vão.' },
      { v: 5, en: 'The fool folds his hands together and ruins himself.', pt: 'O tolo cruza as mãos, e come a sua; própria carne.' },
      { v: 6, en: 'Better is a handful, with quietness, than two handfuls with labor and chasing after wind.', pt: 'Melhor é um punhado com tranqüilidade do que ambas as mãos cheias com trabalho e vão desejo.' },
      { v: 7, en: 'Then I returned and saw vanity under the sun.', pt: 'Outra vez me volvi, e vi vaidade debaixo do sol.' },
      { v: 8, en: 'There is one who is alone, and he has neither son nor brother. There is no end to all of his labor, neither are his eyes satisfied with wealth. “For whom then, do I labor, and deprive my soul of enjoyment?” This also is vanity. Yes, it is a miserable business.', pt: 'Há um que é só, não tendo parente; não tem filho nem irmão e, contudo, de todo o seu trabalho não há fim, nem os seus olhos se fartam de riquezas. E ele não pergunta: Para quem estou trabalhando e privando do bem a minha alma? Também isso é vaidade a e enfadonha ocupação.' },
      { v: 9, en: 'Two are better than one, because they have a good reward for their labor.', pt: 'Melhor é serem dois do que um, porque têm melhor paga do seu trabalho.' },
      { v: 10, en: 'For if they fall, the one will lift up his fellow; but woe to him who is alone when he falls, and doesn’t have another to lift him up.', pt: 'Pois se caírem, um levantará o seu companheiro; mas ai do que estiver só, pois, caindo, não haverá outro que o levante.' },
      { v: 11, en: 'Again, if two lie together, then they have warmth; but how can one keep warm alone?', pt: 'Também, se dois dormirem juntos, eles se aquentarão; mas um só como se aquentará?' },
      { v: 12, en: 'If a man prevails against one who is alone, two shall withstand him; and a threefold cord is not quickly broken.', pt: 'E, se alguém quiser prevalecer contra um, os dois lhe resistirão; e o cordão de três dobras não se quebra tão depressa.' },
      { v: 13, en: 'Better is a poor and wise youth than an old and foolish king who doesn’t know how to receive admonition any more.', pt: 'Melhor é o mancebo pobre e sábio do que o rei velho e insensato, que não se deixa mais admoestar,' },
      { v: 14, en: 'For out of prison he came out to be king; yes, even in his kingdom he was born poor.', pt: 'embora tenha saído do cárcere para reinar, ou tenha nascido pobre no seu próprio reino.' },
      { v: 15, en: 'I saw all the living who walk under the sun, that they were with the youth, the other, who succeeded him.', pt: 'Vi a todos os viventes que andavam debaixo do sol, e eles estavam com o mancebo, o sucessor, que havia de ficar no lugar do rei.' },
      { v: 16, en: 'There was no end of all the people, even of all them over whom he was—yet those who come after shall not rejoice in him. Surely this also is vanity and a chasing after wind.', pt: 'Todo o povo, à testa do qual se achava, era inumerável; contudo os que lhe sucederam não se regozijarão a respeito dele. Na verdade também isso é vaidade e desejo vão.' },
    ],
    5: [
      { v: 1, en: 'Guard your steps when you go to God’s house; for to draw near to listen is better than to give the sacrifice of fools, for they don’t know that they do evil.', pt: 'Guarda o teu pé, quando fores à casa de Deus; porque chegar-se para ouvir é melhor do que oferecer sacrifícios de tolos; pois não sabem que fazem mal.' },
      { v: 2, en: 'Don’t be rash with your mouth, and don’t let your heart be hasty to utter anything before God; for God is in heaven, and you on earth. Therefore let your words be few.', pt: 'Não te precipites com a tua boca, nem o teu coração se apresse a pronunciar palavra alguma na presença de Deus; porque Deus está no céu, e tu estás sobre a terra; portanto sejam poucas as tuas palavras.' },
      { v: 3, en: 'For as a dream comes with a multitude of cares, so a fool’s speech with a multitude of words.', pt: 'Porque, da multidão de trabalhos vêm os sonhos, e da multidão de palavras, a voz do tolo.' },
      { v: 4, en: 'When you vow a vow to God, don’t defer to pay it; for he has no pleasure in fools. Pay that which you vow.', pt: 'Quando a Deus fizeres algum voto, não tardes em cumpri-lo; porque não se agrada de tolos. O que votares, paga-o.' },
      { v: 5, en: 'It is better that you should not vow, than that you should vow and not pay.', pt: 'Melhor é que não votes do que votares e nao pagares.' },
      { v: 6, en: 'Don’t allow your mouth to lead you into sin. Don’t protest before the messenger that this was a mistake. Why should God be angry at your voice, and destroy the work of your hands?', pt: 'Não consintas que a tua boca faça pecar a tua carne, nem digas na presença do anjo que foi erro; por que razão se iraria Deus contra a tua voz, e destruiria a obra das tuas mãos?' },
      { v: 7, en: 'For in the multitude of dreams there are vanities, as well as in many words: but you must fear God.', pt: 'Porque na multidão dos sonhos há vaidades e muitas palavras; mas tu teme a Deus.' },
      { v: 8, en: 'If you see the oppression of the poor, and the violent taking away of justice and righteousness in a district, don’t marvel at the matter: for one official is eyed by a higher one; and there are officials over them.', pt: 'Se vires em alguma província opressão de pobres, e a perversão violenta do direito e da justiça, não te maravilhes de semelhante caso. Pois quem está altamente colocado tem superior que o vigia; e há mais altos ainda sobre eles.' },
      { v: 9, en: 'Moreover the profit of the earth is for all. The king profits from the field.', pt: 'O proveito da terra é para todos; até o rei se serve do campo.' },
      { v: 10, en: 'He who loves silver shall not be satisfied with silver; nor he who loves abundance, with increase: this also is vanity.', pt: 'Quem ama o dinheiro não se fartará de dinheiro; nem o que ama a riqueza se fartará do ganho; também isso é vaidade.' },
      { v: 11, en: 'When goods increase, those who eat them are increased; and what advantage is there to its owner, except to feast on them with his eyes?', pt: 'Quando se multiplicam os bens, multiplicam-se também os que comem; e que proveito tem o seu dono senão o de vê-los com os seus olhos?' },
      { v: 12, en: 'The sleep of a laboring man is sweet, whether he eats little or much; but the abundance of the rich will not allow him to sleep.', pt: 'Doce é o sono do trabalhador, quer coma pouco quer muito; mas a saciedade do rico não o deixa dormir.' },
      { v: 13, en: 'There is a grievous evil which I have seen under the sun: wealth kept by its owner to his harm.', pt: 'Há um grave mal que vi debaixo do sol: riquezas foram guardadas por seu donó para o seu próprio dano;' },
      { v: 14, en: 'Those riches perish by misfortune, and if he has fathered a son, there is nothing in his hand.', pt: 'e as mesmas riquezas se perderam por qualquer má aventura; e havendo algum filho nada fica na sua mão.' },
      { v: 15, en: 'As he came out of his mother’s womb, naked shall he go again as he came, and shall take nothing for his labor, which he may carry away in his hand.', pt: 'Como saiu do ventre de sua mãe, assim também se irá, nu como veio; e nada tomará do seu trabalho, que possa levar na mão.' },
      { v: 16, en: 'This also is a grievous evil, that in all points as he came, so shall he go. And what profit does he have who labors for the wind?', pt: 'Ora isso é um grave mal; porque justamente como veio, assim há de ir; e que proveito lhe vem de ter trabalhado para o vento,' },
      { v: 17, en: 'All his days he also eats in darkness, he is frustrated, and has sickness and wrath.', pt: 'e de haver passado todos os seus dias nas trevas, e de haver padecido muito enfado, enfermidades e aborrecimento?' },
      { v: 18, en: 'Behold, that which I have seen to be good and proper is for one to eat and to drink, and to enjoy good in all his labor, in which he labors under the sun, all the days of his life which God has given him; for this is his portion.', pt: 'Eis aqui o que eu vi, uma boa e bela coisa: alguém comer e beber, e gozar cada um do bem de todo o seu trabalho, com que se afadiga debaixo do sol, todos os dias da vida que Deus lhe deu; pois esse é o seu quinhão.' },
      { v: 19, en: 'Every man also to whom God has given riches and wealth, and has given him power to eat of it, and to take his portion, and to rejoice in his labor—this is the gift of God.', pt: 'E quanto ao homem a quem Deus deu riquezas e bens, e poder para desfrutá-los, receber o seu quinhão, e se regozijar no seu trabalho, isso é dom de Deus.' },
      { v: 20, en: 'For he shall not often reflect on the days of his life; because God occupies him with the joy of his heart.', pt: 'Pois não se lembrará muito dos dias da sua vida; porque Deus lhe enche de alegria o coração.' },
    ],
    6: [
      { v: 1, en: 'There is an evil which I have seen under the sun, and it is heavy on men:', pt: 'Há um mal que tenho visto debaixo do sol, e que pesa muito sobre o homem:' },
      { v: 2, en: 'a man to whom God gives riches, wealth, and honor, so that he lacks nothing for his soul of all that he desires, yet God gives him no power to eat of it, but an alien eats it. This is vanity, and it is an evil disease.', pt: 'um homem a quem Deus deu riquezas, bens e honra, de maneira que nada lhe falta de tudo quanto ele deseja, contudo Deus não lhe dá poder para daí comer, antes o estranho lho come; também isso é vaidade e grande mal.' },
      { v: 3, en: 'If a man fathers a hundred children, and lives many years, so that the days of his years are many, but his soul is not filled with good, and moreover he has no burial; I say, that a stillborn child is better than he:', pt: 'Se o homem gerar cem filhos, e viver muitos anos, de modo que os dias da sua vida sejam muitos, porém se a sua alma não se fartar do bem, e além disso não tiver sepultura, digo que um aborto é melhor do que ele;' },
      { v: 4, en: 'for it comes in vanity, and departs in darkness, and its name is covered with darkness.', pt: 'porquanto debalde veio, e em trevas se vai, e de trevas se cobre o seu nome;' },
      { v: 5, en: 'Moreover it has not seen the sun nor known it. This has rest rather than the other.', pt: 'e ainda que nunca viu o sol, nem o conheceu, mais descanso tem do que o tal;' },
      { v: 6, en: 'Yes, though he live a thousand years twice told, and yet fails to enjoy good, don’t all go to one place?', pt: 'e embora vivesse duas vezes mil anos, mas não gozasse o bem, - não vão todos para um mesmo lugar?' },
      { v: 7, en: 'All the labor of man is for his mouth, and yet the appetite is not filled.', pt: 'Todo o trabalho do homem é para a sua boca, e contudo não se satisfaz o seu apetite.' },
      { v: 8, en: 'For what advantage has the wise more than the fool? What has the poor man, that knows how to walk before the living?', pt: 'Pois, que vantagem tem o sábio sobre o tolo? e que tem o pobre que sabe andar perante os vivos?' },
      { v: 9, en: 'Better is the sight of the eyes than the wandering of the desire. This also is vanity and a chasing after wind.', pt: 'Melhor é a vista dos olhos do que o vaguear da cobiça; também isso é vaidade, e desejo vão.' },
      { v: 10, en: 'Whatever has been, its name was given long ago; and it is known what man is; neither can he contend with him who is mightier than he.', pt: 'Seja qualquer o que for, já há muito foi chamado pelo seu nome; e sabe-se que é homem; e ele não pode contender com o que é mais forte do que ele.' },
      { v: 11, en: 'For there are many words that create vanity. What does that profit man?', pt: 'Visto que as muitas palavras aumentam a vaidade, que vantagem tira delas o homem?' },
      { v: 12, en: 'For who knows what is good for man in life, all the days of his vain life which he spends like a shadow? For who can tell a man what will be after him under the sun?', pt: 'Porque, quem sabe o que é bom nesta vida para o homem, durante os poucos dias da sua vida vã, os quais gasta como sombra? pois quem declarará ao homem o que será depois dele debaixo do sol?' },
    ],
    7: [
      { v: 1, en: 'A good name is better than fine perfume; and the day of death better than the day of one’s birth.', pt: 'Melhor é o bom nome do que o melhor ungüento, e o dia da morte do que o dia do nascimento.' },
      { v: 2, en: 'It is better to go to the house of mourning than to go to the house of feasting: for that is the end of all men, and the living should take this to heart.', pt: 'Melhor é ir à casa onde há luto do que ir a casa onde há banquete; porque naquela se vê o fim de todos os homens, e os vivos o aplicam ao seu coração.' },
      { v: 3, en: 'Sorrow is better than laughter; for by the sadness of the face the heart is made good.', pt: 'Melhor é a mágoa do que o riso, porque a tristeza do rosto torna melhor o coração.' },
      { v: 4, en: 'The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth.', pt: 'O coração dos sábios está na casa do luto, mas o coração dos tolos na casa da alegria.' },
      { v: 5, en: 'It is better to hear the rebuke of the wise, than for a man to hear the song of fools.', pt: 'Melhor é ouvir a repreensão do sábio do que ouvir alguém a canção dos tolos.' },
      { v: 6, en: 'For as the crackling of thorns under a pot, so is the laughter of the fool. This also is vanity.', pt: 'Pois qual o crepitar dos espinhos debaixo da panela, tal é o riso do tolo; também isso é vaidade.' },
      { v: 7, en: 'Surely extortion makes the wise man foolish; and a bribe destroys the understanding.', pt: 'Verdadeiramente a opressão faz endoidecer até o sábio, e a peita corrompe o coração.' },
      { v: 8, en: 'Better is the end of a thing than its beginning. The patient in spirit is better than the proud in spirit.', pt: 'Melhor é o fim duma coisa do que o princípio; melhor é o paciente do que o arrogante.' },
      { v: 9, en: 'Don’t be hasty in your spirit to be angry, for anger rests in the bosom of fools.', pt: 'Não te apresses no teu espírito a irar-te, porque a ira abriga-se no seio dos tolos.' },
      { v: 10, en: 'Don’t say, “Why were the former days better than these?” For you do not ask wisely about this.', pt: 'Não digas: Por que razão foram os dias passados melhores do que estes; porque não provém da sabedoria esta pergunta.' },
      { v: 11, en: 'Wisdom is as good as an inheritance. Yes, it is more excellent for those who see the sun.', pt: 'Tão boa é a sabedoria como a herança, e mesmo de mais proveito para os que vêem o sol.' },
      { v: 12, en: 'For wisdom is a defense, even as money is a defense; but the excellency of knowledge is that wisdom preserves the life of him who has it.', pt: 'Porque a sabedoria serve de defesa, como de defesa serve o dinheiro; mas a excelência da sabedoria é que ela preserva a vida de quem a possui.' },
      { v: 13, en: 'Consider the work of God, for who can make that straight, which he has made crooked?', pt: 'Considera as obras de Deus; porque quem poderá endireitar o que ele fez torto?' },
      { v: 14, en: 'In the day of prosperity be joyful, and in the day of adversity consider; yes, God has made the one side by side with the other, to the end that man should not find out anything after him.', pt: 'No dia da prosperidade regozija-te, mas no dia da adversidade considera; porque Deus fez tanto este como aquele, para que o homem nada descubra do que há de vir depois dele.' },
      { v: 15, en: 'All this I have seen in my days of vanity: there is a righteous man who perishes in his righteousness, and there is a wicked man who lives long in his evildoing.', pt: 'Tudo isto vi nos dias da minha vaidade: há justo que perece na sua justiça, e há ímpio que prolonga os seus dias na sua maldade.' },
      { v: 16, en: 'Don’t be overly righteous, neither make yourself overly wise. Why should you destroy yourself?', pt: 'Não sejas demasiadamente justo, nem demasiadamente sábio; por que te destruirias a ti mesmo?' },
      { v: 17, en: 'Don’t be too wicked, neither be foolish. Why should you die before your time?', pt: 'Não sejas demasiadamente ímpio, nem sejas tolo; por que morrerias antes do teu tempo?' },
      { v: 18, en: 'It is good that you should take hold of this. Yes, also from that don’t withdraw your hand; for he who fears God will come out of them all.', pt: 'Bom é que retenhas isso, e que também daquilo não retires a tua mão; porque quem teme a Deus escapa de tudo isso.' },
      { v: 19, en: 'Wisdom is a strength to the wise man more than ten rulers who are in a city.', pt: 'A sabedoria fortalece ao sábio mais do que dez governadores que haja na cidade.' },
      { v: 20, en: 'Surely there is not a righteous man on earth, who does good and doesn’t sin.', pt: 'Pois não há homem justo sobre a terra, que faça o bem, e nunca peque.' },
      { v: 21, en: 'Also don’t take heed to all words that are spoken, lest you hear your servant curse you;', pt: 'Não escutes a todas as palavras que se disserem, para que não venhas a ouvir o teu servo amaldiçoar-te;' },
      { v: 22, en: 'for often your own heart knows that you yourself have likewise cursed others.', pt: 'pois tu sabes também que muitas vezes tu amaldiçoaste a outros.' },
      { v: 23, en: 'All this I have proved in wisdom. I said, “I will be wise”; but it was far from me.', pt: 'Tudo isto provei-o pela sabedoria; e disse: Far-me-ei sábio; porém a sabedoria ainda ficou longe de mim.' },
      { v: 24, en: 'That which is, is far off and exceedingly deep. Who can find it out?', pt: 'Longe está o que já se foi, e profundíssimo; quem o poderá achar?' },
      { v: 25, en: 'I turned around, and my heart sought to know and to search out, and to seek wisdom and the scheme of things, and to know that wickedness is stupidity, and that foolishness is madness.', pt: 'Eu me volvi, e apliquei o meu coração para saber, e inquirir, e buscar a sabedoria e a razão de tudo, e para conhecer que a impiedade é insensatez e que a estultícia é loucura.' },
      { v: 26, en: 'I find more bitter than death the woman whose heart is snares and traps, whose hands are chains. Whoever pleases God shall escape from her; but the sinner will be ensnared by her.', pt: 'E eu achei uma coisa mais amarga do que a morte, a mulher cujo coração são laços e redes, e cujas mãos são grilhões; quem agradar a Deus escapará dela; mas o pecador virá a ser preso por ela.' },
      { v: 27, en: '“Behold, I have found this,” says the Preacher, “to one another, to find out the scheme;', pt: 'Vedes aqui, isto achei, diz o pregador, conferindo uma coisa com a outra para achar a causa;' },
      { v: 28, en: 'which my soul still seeks; but I have not found. I have found one man among a thousand; but I have not found a woman among all those.', pt: 'causa que ainda busco, mas não a achei; um homem entre mil achei eu, mas uma mulher entre todas, essa não achei.' },
      { v: 29, en: 'Behold, I have only found this: that God made man upright; but they search for many schemes.”', pt: 'Eis que isto tão-somente achei: que Deus fez o homem reto, mas os homens buscaram muitos artifícios.' },
    ],
    8: [
      { v: 1, en: 'Who is like the wise man? And who knows the interpretation of a thing? A man’s wisdom makes his face shine, and the hardness of his face is changed.', pt: 'Quem é como o sábio? e quem sabe a interpretação das coisas? A sabedoria do homem faz brilhar o seu rosto, e com ela a dureza do seu rosto se transforma.' },
      { v: 2, en: 'I say, “Keep the king’s command!” because of the oath to God.', pt: 'Eu digo: Observa o mandamento do rei, e isso por causa do juramento a Deus.' },
      { v: 3, en: 'Don’t be hasty to go out of his presence. Don’t persist in an evil thing, for he does whatever pleases him,', pt: 'Não te apresses a sair da presença dele; nem persistas em alguma coisa má; porque ele faz tudo o que lhe agrada.' },
      { v: 4, en: 'for the king’s word is supreme. Who can say to him, “What are you doing?”', pt: 'Porque a palavra do rei é suprema; e quem lhe dirá: que fazes?' },
      { v: 5, en: 'Whoever keeps the commandment shall not come to harm, and his wise heart will know the time and procedure.', pt: 'Quem guardar o mandamento não experimentará nenhum mal; e o coração do sábio discernirá o tempo e o juízo.' },
      { v: 6, en: 'For there is a time and procedure for every purpose, although the misery of man is heavy on him.', pt: 'Porque para todo propósito há tempo e juízo; porquanto a miséria do homem pesa sobre ele.' },
      { v: 7, en: 'For he doesn’t know that which will be; for who can tell him how it will be?', pt: 'Porque não sabe o que há de suceder; pois quem lho dará a entender como há de ser?' },
      { v: 8, en: 'There is no man who has power over the spirit to contain the spirit; neither does he have power over the day of death. There is no discharge in war; neither shall wickedness deliver those who practice it.', pt: 'Nenhum homem há que tenha domínio sobre o espírito, para o reter; nem que tenha poder sobre o dia da morte; nem há licença em tempo de guerra; nem tampouco a impiedade livrará aquele que a ela está entregue.' },
      { v: 9, en: 'All this I have seen, and applied my mind to every work that is done under the sun. There is a time in which one man has power over another to his hurt.', pt: 'Tudo isto tenho observado enquanto aplicava o meu coração a toda obra que se faz debaixo do sol; tempo há em que um homem tem domínio sobre outro homem para o seu próprio dano.' },
      { v: 10, en: 'So I saw the wicked buried. Indeed they came also from holiness. They went and were forgotten in the city where they did this. This also is vanity.', pt: 'Vi também os ímpios sepultados, os que antes entravam e saíam do lugar santo; e foram esquecidos na cidade onde haviam assim procedido; também isso é vaidade.' },
      { v: 11, en: 'Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil.', pt: 'Porquanto não se executa logo o juízo sobre a má obra, o coração dos filhos dos homens está inteiramente disposto para praticar o mal.' },
      { v: 12, en: 'Though a sinner commits crimes a hundred times, and lives long, yet surely I know that it will be better with those who fear God, who are reverent before him.', pt: 'Ainda que o pecador faça o mal cem vezes, e os dias se lhe prolonguem, contudo eu sei com certeza que bem sucede aos que temem a Deus, porque temem diante dele;' },
      { v: 13, en: 'But it shall not be well with the wicked, neither shall he lengthen days like a shadow; because he doesn’t fear God.', pt: 'ao ímpio, porém, não irá bem, e ele não prolongará os seus dias, que são como a sombra; porque ele não teme diante de Deus.' },
      { v: 14, en: 'There is a vanity which is done on the earth, that there are righteous men to whom it happens according to the work of the wicked. Again, there are wicked men to whom it happens according to the work of the righteous. I said that this also is vanity.', pt: 'Ainda há outra vaidade que se faz sobre a terra: há justos a quem sucede segundo as obras dos ímpios, e há ímpios a quem sucede segundo as obras dos justos. Eu disse que também isso é vaidade.' },
      { v: 15, en: 'Then I commended mirth, because a man has no better thing under the sun, than to eat, and to drink, and to be joyful: for that will accompany him in his labor all the days of his life which God has given him under the sun.', pt: 'Exalto, pois, a alegria, porquanto o homem nenhuma coisa melhor tem debaixo do sol do que comer, beber e alegrar-se; porque isso o acompanhará no seu trabalho nos dias da sua vida que Deus lhe dá debaixo do sol.' },
      { v: 16, en: 'When I applied my heart to know wisdom, and to see the business that is done on the earth (for also there is that neither day nor night sees sleep with his eyes),', pt: 'Quando apliquei o meu coração a conhecer a sabedoria, e a ver o trabalho que se faz sobre a terra (pois homens há que nem de dia nem de noite conseguem dar sono aos seus olhos),' },
      { v: 17, en: 'then I saw all the work of God, that man can’t find out the work that is done under the sun, because however much a man labors to seek it out, yet he won’t find it. Yes even though a wise man thinks he can comprehend it, he won’t be able to find it.', pt: 'então contemplei toda obra de Deus, e vi que o homem não pode compreender a obra que se faz debaixo do sol; pois por mais que o homem trabalhe para a descobrir, não a achará; embora o sábio queira conhecê-la, nem por isso a poderá compreender.' },
    ],
    9: [
      { v: 1, en: 'For all this I laid to my heart, even to explore all this: that the righteous, and the wise, and their works, are in the hand of God; whether it is love or hatred, man doesn’t know it; all is before them.', pt: 'Deveras a tudo isto apliquei o meu coração, para claramente entender tudo isto: que os justos, e os sábios, e as suas obras, estão nas mãos de Deus; se é amor ou se é ódio, não o sabe o homem; tudo passa perante a sua face.' },
      { v: 2, en: 'All things come alike to all. There is one event to the righteous and to the wicked; to the good, to the clean, to the unclean, to him who sacrifices, and to him who doesn’t sacrifice. As is the good, so is the sinner; he who takes an oath, as he who fears an oath.', pt: 'Tudo sucede igualmente a todos: o mesmo sucede ao justo e ao ímpio, ao bom e ao mau, ao puro e ao impuro; assim ao que sacrifica como ao que não sacrifica; assim ao bom como ao pecador; ao que jura como ao que teme o juramento.' },
      { v: 3, en: 'This is an evil in all that is done under the sun, that there is one event to all: yes also, the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead.', pt: 'Este é o mal que há em tudo quanto se faz debaixo do sol: que a todos sucede o mesmo. Também o coração dos filhos dos homens está cheio de maldade; há desvarios no seu coração durante a sua vida, e depois se vão aos mortos.' },
      { v: 4, en: 'For to him who is joined with all the living there is hope; for a living dog is better than a dead lion.', pt: 'Ora, para aquele que está na companhia dos vivos há esperança; porque melhor é o cão vivo do que o leão morto.' },
      { v: 5, en: 'For the living know that they will die, but the dead don’t know anything, neither do they have any more a reward; for their memory is forgotten.', pt: 'Pois os vivos sabem que morrerão, mas os mortos não sabem coisa nenhuma, nem tampouco têm eles daí em diante recompensa; porque a sua memória ficou entregue ao esquecimento.' },
      { v: 6, en: 'Also their love, their hatred, and their envy has perished long ago; neither have they any more a portion forever in anything that is done under the sun.', pt: 'Tanto o seu amor como o seu ódio e a sua inveja já pereceram; nem têm eles daí em diante parte para sempre em coisa alguma do que se faz debaixo do sol.' },
      { v: 7, en: 'Go your way—eat your bread with joy, and drink your wine with a merry heart; for God has already accepted your works.', pt: 'Vai, pois, come com alegria o teu pão .e bebe o teu vinho com coração contente; pois há muito que Deus se agrada das tuas obras.' },
      { v: 8, en: 'Let your garments be always white, and don’t let your head lack oil.', pt: 'Sejam sempre alvas as tuas vestes, e nunca falte o óleo sobre a tua cabeça.' },
      { v: 9, en: 'Live joyfully with the wife whom you love all the days of your life of vanity, which he has given you under the sun, all your days of vanity: for that is your portion in life, and in your labor in which you labor under the sun.', pt: 'Goza a vida com a mulher que amas, todos os dias da tua vida vã, os quais Deus te deu debaixo do sol, todos os dias da tua vida vã; porque este é o teu quinhão nesta vida, e do teu trabalho, que tu fazes debaixo do sol.' },
      { v: 10, en: 'Whatever your hand finds to do, do it with your might; for there is no work, nor plan, nor knowledge, nor wisdom, in Sheol, where you are going.', pt: 'Tudo quanto te vier à mão para fazer, faze-o conforme as tuas forças; porque no Seol, para onde tu vais, não há obra, nem projeto, nem conhecimento, nem sabedoria alguma.' },
      { v: 11, en: 'I returned, and saw under the sun, that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favor to men of skill; but time and chance happen to them all.', pt: 'Observei ainda e vi que debaixo do sol não é dos ligeiros a carreira, nem dos fortes a peleja, nem tampouco dos sábios o pão, nem ainda dos prudentes a riqueza, nem dos entendidos o favor; mas que a ocasião e a sorte ocorrem a todos.' },
      { v: 12, en: 'For man also doesn’t know his time. As the fish that are taken in an evil net, and as the birds that are caught in the snare, even so are the sons of men snared in an evil time, when it falls suddenly on them.', pt: 'Pois o homem não conhece a sua hora. Como os peixes que se apanham com a rede maligna, e como os passarinhos que se prendem com o laço, assim se enlaçam também os filhos dos homens no mau tempo, quando este lhes sobrevém de repente.' },
      { v: 13, en: 'I have also seen wisdom under the sun in this way, and it seemed great to me.', pt: 'Também vi este exemplo de sabedoria debaixo do sol, que me pareceu grande:' },
      { v: 14, en: 'There was a little city, and few men within it; and a great king came against it, besieged it, and built great bulwarks against it.', pt: 'Houve uma pequena cidade em que havia poucos homens; e veio contra ela um grande rei, e a cercou e levantou contra ela grandes tranqueiras.' },
      { v: 15, en: 'Now a poor wise man was found in it, and he by his wisdom delivered the city; yet no man remembered that same poor man.', pt: 'Ora, achou-se nela um sábio pobre, que livrou a cidade pela sua sabedoria; contudo ninguém se lembrou mais daquele homem pobre.' },
      { v: 16, en: 'Then I said, “Wisdom is better than strength.” Nevertheless the poor man’s wisdom is despised, and his words are not heard.', pt: 'Então disse eu: Melhor é a sabedoria do que a força; todavia a sabedoria do pobre é desprezada, e as suas palavras não são ouvidas.' },
      { v: 17, en: 'The words of the wise heard in quiet are better than the cry of him who rules among fools.', pt: 'As palavras dos sábios ouvidas em silêncio valem mais do que o clamor de quem governa entre os tolos.' },
      { v: 18, en: 'Wisdom is better than weapons of war; but one sinner destroys much good.', pt: 'Melhor é a sabedoria do que as armas de guerra; mas um só pecador faz grande dano ao bem.' },
    ],
    10: [
      { v: 1, en: 'Dead flies cause the oil of the perfumer to produce an evil odor; so does a little folly outweigh wisdom and honor.', pt: 'As moscas mortas fazem com que o ungüento do perfumista emita mau cheiro; assim um pouco de estultícia pesa mais do que a sabedoria e a honra.' },
      { v: 2, en: 'A wise man’s heart is at his right hand, but a fool’s heart at his left.', pt: 'O coração do sábio o inclina para a direita, mas o coração do tolo o inclina para a esquerda.' },
      { v: 3, en: 'Yes also, when the fool walks by the way, his understanding fails him, and he says to everyone that he is a fool.', pt: 'E, até quando o tolo vai pelo caminho, falta-lhe o entendimento, e ele diz a todos que é tolo.' },
      { v: 4, en: 'If the spirit of the ruler rises up against you, don’t leave your place; for gentleness lays great offenses to rest.', pt: 'Se se levantar contra ti o espírito do governador, não deixes o teu lugar; porque a deferência desfaz grandes ofensas.' },
      { v: 5, en: 'There is an evil which I have seen under the sun, the sort of error which proceeds from the ruler.', pt: 'Há um mal que vi debaixo do sol, semelhante a um erro que procede do governador:' },
      { v: 6, en: 'Folly is set in great dignity, and the rich sit in a low place.', pt: 'a estultícia está posta em grande dignidade, e os ricos estão assentados em lugar humilde.' },
      { v: 7, en: 'I have seen servants on horses, and princes walking like servants on the earth.', pt: 'Tenho visto servos montados a cavalo, e príncipes andando a pé como servos.' },
      { v: 8, en: 'He who digs a pit may fall into it; and whoever breaks through a wall may be bitten by a snake.', pt: 'Aquele que abrir uma cova, nela cairá; e quem romper um muro, uma cobra o morderá.' },
      { v: 9, en: 'Whoever carves out stones may be injured by them. Whoever splits wood may be endangered thereby.', pt: 'Aquele que tira pedras é maltratado por elas, e o que racha lenha corre perigo nisso.' },
      { v: 10, en: 'If the ax is blunt, and one doesn’t sharpen the edge, then he must use more strength; but skill brings success.', pt: 'Se estiver embotado o ferro, e não se afiar o corte, então se deve pôr mais força; mas a sabedoria é proveitosa para dar prosperidade.' },
      { v: 11, en: 'If the snake bites before it is charmed, then is there no profit for the charmer’s tongue.', pt: 'Se a cobra morder antes de estar encantada, não há vantagem no encantador.' },
      { v: 12, en: 'The words of a wise man’s mouth are gracious; but a fool is swallowed by his own lips.', pt: 'As palavras da boca do sábio são cheias de graça, mas os lábios do tolo o devoram.' },
      { v: 13, en: 'The beginning of the words of his mouth is foolishness; and the end of his talk is mischievous madness.', pt: 'O princípio das palavras da sua boca é estultícia, e o fim do seu discurso é loucura perversa.' },
      { v: 14, en: 'A fool also multiplies words. Man doesn’t know what will be; and that which will be after him, who can tell him?', pt: 'O tolo multiplica as palavras, todavia nenhum homem sabe o que há de ser; e quem lhe poderá declarar o que será depois dele?' },
      { v: 15, en: 'The labor of fools wearies every one of them; for he doesn’t know how to go to the city.', pt: 'O trabalho do tolo o fatiga, de sorte que não sabe ir à cidade.' },
      { v: 16, en: 'Woe to you, land, when your king is a child, and your princes eat in the morning!', pt: 'Ai de ti, ó terra, quando o teu rei é criança, e quando os teus príncipes banqueteiam de manhã!' },
      { v: 17, en: 'Happy are you, land, when your king is the son of nobles, and your princes eat in due season, for strength, and not for drunkenness!', pt: 'Bem-aventurada tu, ó terra, quando o teu rei é filho de nobres, e quando os teus príncipes comem a tempo, para refazerem as forças, e não para bebedice!' },
      { v: 18, en: 'By slothfulness the roof sinks in; and through idleness of the hands the house leaks.', pt: 'Pela preguiça se enfraquece o teto, e pela frouxidão das mãos a casa tem goteiras.' },
      { v: 19, en: 'A feast is made for laughter, and wine makes the life glad; and money is the answer for all things.', pt: 'Para rir é que se dá banquete, e o vinho alegra a vida; e por tudo o dinheiro responde.' },
      { v: 20, en: 'Don’t curse the king, no, not in your thoughts; and don’t curse the rich in your bedroom: for a bird of the sky may carry your voice, and that which has wings may tell the matter.', pt: 'Nem ainda no teu pensamento amaldições o rei; nem tampouco na tua recâmara amaldiçoes o rico; porque as aves dos céus levarão a voz, e uma criatura alada dará notícia da palavra.' },
    ],
    11: [
      { v: 1, en: 'Cast your bread on the waters; for you shall find it after many days.', pt: 'Lança o teu pão sobre as águas, porque depois de muitos dias o acharás.' },
      { v: 2, en: 'Give a portion to seven, yes, even to eight; for you don’t know what evil will be on the earth.', pt: 'Reparte com sete, e ainda até com oito; porque não sabes que mal haverá sobre a terra.' },
      { v: 3, en: 'If the clouds are full of rain, they empty themselves on the earth; and if a tree falls toward the south, or toward the north, in the place where the tree falls, there shall it be.', pt: 'Estando as nuvens cheias de chuva, derramam-na sobre a terra. Caindo a árvore para o sul, ou para o norte, no lugar em que a árvore cair, ali ficará.' },
      { v: 4, en: 'He who observes the wind won’t sow; and he who regards the clouds won’t reap.', pt: 'Quem observa o vento, não semeará, e o que atenta para as nuvens não segará.' },
      { v: 5, en: 'As you don’t know what is the way of the wind, nor how the bones grow in the womb of her who is with child; even so you don’t know the work of God who does all.', pt: 'Assim como tu não sabes qual o caminho do vento, nem como se formam os ossos no ventre da que está grávida, assim também não sabes as obras de Deus, que faz todas as coisas.' },
      { v: 6, en: 'In the morning sow your seed, and in the evening don’t withhold your hand; for you don’t know which will prosper, whether this or that, or whether they both will be equally good.', pt: 'Pela manhã semeia a tua semente, e à tarde não retenhas a tua mão; pois tu não sabes qual das duas prosperará, se esta, se aquela, ou se ambas serão, igualmente boas.' },
      { v: 7, en: 'Truly the light is sweet, and a pleasant thing it is for the eyes to see the sun.', pt: 'Doce é a luz, e agradável é aos olhos ver o sol.' },
      { v: 8, en: 'Yes, if a man lives many years, let him rejoice in them all; but let him remember the days of darkness, for they shall be many. All that comes is vanity.', pt: 'Se, pois, o homem viver muitos anos, regozije-se em todos eles; contudo lembre-se dos dias das trevas, porque hão de ser muitos. Tudo quanto sucede é vaidade.' },
      { v: 9, en: 'Rejoice, young man, in your youth, and let your heart cheer you in the days of your youth, and walk in the ways of your heart, and in the sight of your eyes; but know that for all these things God will bring you into judgment.', pt: 'Alegra-te, mancebo, na tua mocidade, e anime-te o teu coração nos dias da tua mocidade, e anda pelos caminhos do teu coração, e pela vista dos teus olhos; sabe, porém, que por todas estas coisas Deus te trará a juízo.' },
      { v: 10, en: 'Therefore remove sorrow from your heart, and put away evil from your flesh; for youth and the dawn of life are vanity.', pt: 'Afasta, pois, do teu coração o desgosto, remove da tua carne o mal; porque a mocidade e a aurora da vida são vaidade.' },
    ],
    12: [
      { v: 1, en: 'Remember also your Creator in the days of your youth, before the evil days come, and the years draw near, when you will say, “I have no pleasure in them”;', pt: 'Lembra-te também do teu Criador nos dias da tua mocidade, antes que venham os maus dias, e cheguem os anos em que dirás: Não tenho prazer neles;' },
      { v: 2, en: 'Before the sun, the light, the moon, and the stars are darkened, and the clouds return after the rain;', pt: 'antes que se escureçam o sol e a luz, e a lua, e as estrelas, e tornem a vir as nuvens depois da chuva;' },
      { v: 3, en: 'in the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those who look out of the windows are darkened,', pt: 'no dia em que tremerem os guardas da casa, e se curvarem os homens fortes, e cessarem os moedores, por já serem poucos, e se escurecerem os que olham pelas janelas,' },
      { v: 4, en: 'and the doors shall be shut in the street; when the sound of the grinding is low, and one shall rise up at the voice of a bird, and all the daughters of music shall be brought low;', pt: 'e as portas da rua se fecharem; quando for baixo o ruído da moedura, e nos levantarmos à voz das aves, e todas as filhas da música ficarem abatidas;' },
      { v: 5, en: 'yes, they shall be afraid of heights, and terrors will be on the way; and the almond tree shall blossom, and the grasshopper shall be a burden, and desire shall fail; because man goes to his everlasting home, and the mourners go about the streets:', pt: 'como também quando temerem o que é alto, e houver espantos no caminho; e florescer a amendoeira, e o gafanhoto for um peso, e falhar o desejo; porque o homem se vai à sua casa eterna, e os pranteadores andarão rodeando pela praça;' },
      { v: 6, en: 'before the silver cord is severed, or the golden bowl is broken, or the pitcher is broken at the spring, or the wheel broken at the cistern,', pt: 'antes que se rompa a cadeia de prata, ou se quebre o copo de ouro, ou se despedace o cântaro junto à fonte, ou se desfaça a roda junto à cisterna,' },
      { v: 7, en: 'and the dust returns to the earth as it was, and the spirit returns to God who gave it.', pt: 'e o pó volte para a terra como o era, e o espírito volte a Deus que o deu.' },
      { v: 8, en: '“Vanity of vanities,” says the Preacher. “All is vanity!”', pt: 'Vaidade de vaidades, diz o pregador, tudo é vaidade.' },
      { v: 9, en: 'Further, because the Preacher was wise, he still taught the people knowledge. Yes, he pondered, sought out, and set in order many proverbs.', pt: 'Além de ser sábio, o pregador também ensinou ao povo o conhecimento, meditando, e estudando, e pondo em ordem muitos provérbios.' },
      { v: 10, en: 'The Preacher sought to find out acceptable words, and that which was written blamelessly, words of truth.', pt: 'Procurou o pregador achar palavras agradáveis, e escreveu com acerto discursos plenos de verdade.' },
      { v: 11, en: 'The words of the wise are like goads; and like nails well fastened are words from the masters of assemblies, which are given from one shepherd.', pt: 'As palavras dos sábios são como aguilhões; e como pregos bem fixados são as palavras coligidas dos mestres, as quais foram dadas pelo único pastor.' },
      { v: 12, en: 'Furthermore, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh.', pt: 'Além disso, filho meu, sê avisado. De fazer muitos livros não há fim; e o muito estudar é enfado da carne.' },
      { v: 13, en: 'This is the end of the matter. All has been heard. Fear God, and keep his commandments; for this is the whole duty of man.', pt: 'Este é o fim do discurso; tudo já foi ouvido: Teme a Deus, e guarda os seus mandamentos; porque isto é todo o dever do homem.' },
      { v: 14, en: 'For God will bring every work into judgment, with every hidden thing, whether it is good, or whether it is evil.', pt: 'Porque Deus há de trazer a juízo toda obra, e até tudo o que está encoberto, quer seja bom, quer seja mau.' },
    ],
  },
};

export default book;
